-- Metabolic matrix v2.8: pathway geometry and dependency edges.
-- Additive/idempotent. Existing pathway rules are intentionally preserved.
-- The React SVG cards remain the visual source of truth; nodes/edges are the
-- database fallback for auto-layout, printing and server-side catalog context.

ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  is_active = true,
  nodes = EXCLUDED.nodes,
  edges = EXCLUDED.edges,
  "group" = EXCLUDED."group",
  group_order = EXCLUDED.group_order,
  updated_at = now();

-- Do not insert severity rules here: the clinical matrix explicitly marks
-- these v2.8 pathway cards as context/display-only until separate rules are
-- approved by the physician.
